#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

typedef struct {
    char entry[REC_LENGTH];
    float dist;
} neighbor_t;

// Robust float parser matching atof behavior for the specific fixed-width format
float parse_float_safe(const char *str, int len) {
    float val = 0.0f;
    float frac = 0.0f;
    int sign = 1;
    int i = 0;

    // Skip leading whitespace
    while (i < len && (str[i] == ' ' || str[i] == '\t')) {
        i++;
    }

    if (i >= len) return 0.0f;

    // Sign
    if (str[i] == '-') {
        sign = -1;
        i++;
    } else if (str[i] == '+') {
        i++;
    }

    if (i >= len) return 0.0f;

    // Integer part
    while (i < len && str[i] >= '0' && str[i] <= '9') {
        val = val * 10.0f + (str[i] - '0');
        i++;
    }

    // Fractional part
    if (i < len && str[i] == '.') {
        i++;
        float divisor = 10.0f;
        while (i < len && str[i] >= '0' && str[i] <= '9') {
            frac += (str[i] - '0') / divisor;
            divisor *= 10.0f;
            i++;
        }
    }

    return sign * (val + frac);
}

__kernel void compute_distances(
    const char *sandbox,
    float *z,
    float target_lat,
    float target_long,
    int rec_count)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    int base_idx = i * REC_LENGTH;

    // Latitude starts at index 27 (LATITUDE_POS - 1)
    // We pass the pointer to the start of the record and the offset
    float tmp_lat = parse_float_safe(sandbox + base_idx, REC_LENGTH - base_idx % REC_LENGTH); 
    // Actually, just passing the offset is safer. 
    // Let's re-calculate offset logic inside.

    // Lat is at offset 27 relative to record start.
    // Lon is at offset 33 relative to record start (after skipping space at 32).
    // But atof(rec_iter+5) where rec_iter is at 27 -> offset 32. atof skips space.

    float tmp_lat_val = parse_float_safe(sandbox + base_idx + 27, 6);
    float tmp_long_val = parse_float_safe(sandbox + base_idx + 32, 6);

    float diff_lat = tmp_lat_val - target_lat;
    float diff_long = tmp_long_val - target_long;

    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

__kernel void update_neighbors(
    const char *sandbox,
    const float *z,
    neighbor_t *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance (the one to potentially replace)
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    // If the current record is closer than the farthest neighbor, replace it
    if (current_dist < max_dist) {
        // Copy the record string
        int base_idx = i * REC_LENGTH;
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            neighbors[max_idx].entry[c] = sandbox[base_idx + c];
        }
        neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
        neighbors[max_idx].dist = current_dist;
    }
}
